function setTheme(theme) {
  document.documentElement.dataset.theme = theme;
}

el.addEventListener('pointermove', (e) => {
  const rect = el.getBoundingClientRect();
  el.style.setProperty('--mx', `${e.clientX - rect.left}px`);
  el.style.setProperty('--my', `${e.clientY - rect.top}px`);
});

:root {
  color-scheme: light dark;
  --bg: #ffffff;
  --fg: #1a202c;
}

[data-theme="dark"], :root:has([data-theme="dark"]) {
  --bg: #0f172a;
  --fg: #f1f5f9;
}

@media (prefers-color-scheme: dark) {
  :root:not([data-theme="light"]) {
    --bg: #0f172a;
    --fg: #f1f5f9;
  }
}

body { background: var(--bg); color: var(--fg); }

/* skip rendering off-screen sections */
.section { content-visibility: auto; contain-intrinsic-size: 400px; }

/* hint to browser about an upcoming animation */
.card.entering { will-change: transform; }

/* prefer cheap animations */
.card { transition: transform 0.2s; }   /* good */
