@layer reset, tokens, base, components, utilities;

@layer reset {
  *, *::before, *::after { box-sizing: border-box; }
  * { margin: 0; }
}

@layer tokens {
  :root {
    --space-4: 1rem;
    --radius: 0.5rem;
    --color-brand: #4f46e5;
    --font-body: 'Inter', system-ui, sans-serif;
  }
}

@layer base {
  body { font-family: var(--font-body); line-height: 1.5; }
}
